  def format_object(obj: str) -> str:
          """Pretty‑print objects that contain comma‑separated lists.
          Splits only on commas followed by a space to avoid breaking numbers
          like “1,234” while still handling lists such as “234, 330”. """
          if ", " in obj:
              parts = [p.strip() for p in obj.split(", ")]
              if len(parts) > 1:
                  return ", ".join(parts[:-1]) + " and " + parts[-1]
          return obj.strip()
